import React, { useState, useEffect, useMemo } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { v4 as uuidv4 } from "uuid";
import Footer from "./Footer";
import { useDispatch, useSelector } from "react-redux";
import { base_url } from "./../utils/axiosConfig";
import { getCart, clearCart } from "../redux/actions/cartAction";
import { toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

function Checkout() {
  const [input, setInput] = useState({
    firstname: "",
    lastname: "",
    email: "",
    phone: "",
    address: "",
    city: "",
    country: "",
    postalCode: "",
  });
  const handleChange = (e) => {
    setInput({ ...input, [e.target.name]: e.target.value });
  };

  const getTokenFromLocalStorage = useMemo(() => {
    return localStorage.getItem("customer")
      ? JSON.parse(localStorage.getItem("customer"))
      : null;
  }, []);

  const config2 = useMemo(
    () => ({
      headers: {
        Authorization: `Bearer ${getTokenFromLocalStorage ? getTokenFromLocalStorage.token : ""}`,
        Accept: "application/json",
      },
    }),
    [getTokenFromLocalStorage],
  );

  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const [cartItems, setCartItems] = useState([]);
  const [totalAmount, setTotalAmount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [uploadingPrescription, setUploadingPrescription] = useState(false);
  const [prescriptionImages, setPrescriptionImages] = useState([]);

  const { items } = useSelector((state) => state.cart);
  const productFromBuyNow = location.state;

  useEffect(() => {
    setCartItems(items);
  }, [items]);
  useEffect(() => {
    let sum = 0;
    cartItems.forEach((item) => {
      sum += item.quantity * item.productId.price;
    });
    setTotalAmount(sum);
  }, [cartItems]);
  useEffect(() => {
    dispatch(getCart());
  }, [dispatch]);

  // Load prescriptions from Product page if any
  useEffect(() => {
    const preUploads = sessionStorage.getItem("pendingPrescriptions");
    if (preUploads) {
      try {
        const parsed = JSON.parse(preUploads);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setPrescriptionImages(parsed);
          toast.info(`📎 Attached ${parsed.length} prescription image(s) from product page.`);
          // Clear sessionStorage after loading to avoid re-adding
          sessionStorage.removeItem("pendingPrescriptions");
        }
      } catch (e) {
        console.error("Prescription load error:", e);
      }
    }
  }, []);

  const requiresPrescription = useMemo(() => {
    return cartItems.some((item) => item?.productId?.requiresPrescription);
  }, [cartItems]);

  const handlePrescriptionUpload = async (e) => {
    const files = Array.from(e.target.files);
    if (files.length === 0) return;
    setUploadingPrescription(true);
    try {
      const formData = new FormData();
      files.forEach((file) => formData.append("multiple_image", file));
      const response = await fetch(`${base_url}upload/create`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${getTokenFromLocalStorage ? getTokenFromLocalStorage.token : ""}`,
        },
        body: formData,
      });
      const data = await response.json();
      if (data && data.length > 0) {
        setPrescriptionImages((prev) => [...prev, ...data]);
        toast.success("Prescription uploaded successfully!");
      } else {
        throw new Error("Invalid response format");
      }
    } catch (error) {
      console.error("Upload error", error);
      toast.error("Failed to upload prescription. Please try again.");
    }
    setUploadingPrescription(false);
  };

  const handleChapa = async (e) => {
    e.preventDefault();

    if (requiresPrescription && prescriptionImages.length === 0) {
      toast.error("Please upload a prescription for the required items in your cart.");
      return;
    }

    setLoading(true);
    const txRef = `pulseaddis-${uuidv4()}`;
    try {
      const response = await fetch(`${base_url}payment/initialize`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${getTokenFromLocalStorage ? getTokenFromLocalStorage.token : ""}`,
        },
        credentials: "include",
        body: JSON.stringify({
          amount: totalAmount,
          currency: "ETB",
          email: input.email,
          first_name: input.firstname,
          last_name: input.lastname,
          address: input.address,
          city: input.city,
          tx_ref: txRef,
          country: input.country,
          postalCode: input.postalCode,
          phone_number: input.phone,
          cart: cartItems.map((item) => ({
            product: item.productId._id,
            postedByUserId: item.postedByUserId,
            color: item.selectedColor,
            quantity: item.quantity,
            size: item.selectedSize,
            price: item.productId.price,
          })),
          totalPrice: totalAmount,
          totalPriceAfterDiscount: totalAmount,
          prescriptionImages: requiresPrescription ? prescriptionImages : [],
          prescriptionStatus: requiresPrescription ? "pending" : "not_required",
        }),
      });

      if (!response.ok) throw new Error("Payment initialization failed");
      dispatch(clearCart());
      setLoading(false);
      toast.success("Redirecting to Chapa for payment...");

      const data = await response.json();
      if (data.payment_url) {
        window.location.href = data.payment_url;
      } else {
        toast.error("Payment failed. Please try again.");
      }
    } catch (error) {
      setLoading(false);
      console.error("Checkout error:", error);
      toast.error("Checkout failed. Please check your details and try again.");
    }
  };

  const inputStyle = {
    width: "100%",
    padding: "14px 18px",
    fontSize: "14px",
    fontWeight: "500",
    color: "#111827",
    background: "#f8fafc",
    border: "1.5px solid #e2e8f0",
    borderRadius: "14px",
    outline: "none",
    transition: "all 0.2s ease",
  };

  const inputFocusHandler = (e) => {
    e.target.style.borderColor = "#14b8a6";
    e.target.style.background = "#ffffff";
    e.target.style.boxShadow = "0 0 0 3px rgba(20,184,166,0.1)";
  };
  const inputBlurHandler = (e) => {
    e.target.style.borderColor = "#e2e8f0";
    e.target.style.background = "#f8fafc";
    e.target.style.boxShadow = "none";
  };

  return (
    <>
      <style>{`
        @keyframes chkFadeIn {
          from { opacity: 0; transform: translateY(16px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes chkSpin {
          to { transform: rotate(360deg); }
        }
        .chk-card { animation: chkFadeIn 0.5s ease both; }

        .chk-main { max-width: 1100px; margin: 0 auto; padding: 40px 24px 80px; }
        .chk-grid { display: flex; gap: 32px; align-items: flex-start; }
        .chk-left { flex: 1; min-width: 0; }
        .chk-right { width: 380px; flex-shrink: 0; position: sticky; top: 100px; }

        @media (max-width: 900px) {
          .chk-grid { flex-direction: column !important; }
          .chk-right { width: 100% !important; position: relative !important; top: 0 !important; }
          .chk-main { padding: 32px 16px 60px !important; }
          .chk-hero { padding: 60px 20px 40px !important; }
          .chk-hero-title { font-size: 24px !important; }
        }

        @media (max-width: 480px) {
          .chk-steps { gap: 4px !important; flex-wrap: wrap !important; }
          .chk-step-item { font-size: 9px !important; }
          .chk-step-btn { padding: 3px 6px !important; }
        }
      `}</style>

      <main style={{ background: "#ffffff", minHeight: "100vh" }}>
        {/* Loading Overlay */}
        {loading && (
          <div
            style={{
              position: "fixed",
              inset: 0,
              zIndex: 9999,
              background: "rgba(255,255,255,0.85)",
              backdropFilter: "blur(6px)",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              gap: "20px",
            }}
          >
            <div
              style={{ position: "relative", width: "80px", height: "80px" }}
            >
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  border: "4px solid #f1f5f9",
                  borderTopColor: "#14b8a6",
                  borderRadius: "50%",
                  animation: "chkSpin 0.8s linear infinite",
                }}
              />
              <img
                src="/logo3.png"
                alt="Pulse Addis"
                style={{
                  position: "absolute",
                  top: "50%",
                  left: "50%",
                  transform: "translate(-50%, -50%)",
                  width: "48px",
                  height: "48px",
                  borderRadius: "50%",
                  objectFit: "cover",
                }}
              />
            </div>
            <span
              style={{
                fontSize: "14px",
                fontWeight: "700",
                color: "#0d9488",
                letterSpacing: "0.05em",
              }}
            >
              Processing your order...
            </span>
          </div>
        )}

        {/* Hero Header */}
        <section
          className="chk-hero"
          style={{
            background: "linear-gradient(135deg, #14b8a6 0%, #0d9488 100%)",
            padding: "40px 20px 24px",
            textAlign: "center",
            position: "relative",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              position: "absolute",
              top: "-60px",
              right: "-60px",
              width: "200px",
              height: "200px",
              background:
                "radial-gradient(circle, rgba(255,255,255,0.08) 0%, transparent 70%)",
              pointerEvents: "none",
            }}
          />
          <div style={{ position: "relative", zIndex: 2 }}>
            <h1
              className="chk-hero-title"
              style={{
                fontSize: "clamp(20px, 3.5vw, 28px)",
                fontWeight: "900",
                color: "#ffffff",
                margin: "0 0 4px",
                letterSpacing: "-0.5px",
              }}
            >
              Secure Checkout
            </h1>
            <p
              style={{
                fontSize: "12px",
                fontWeight: "500",
                color: "rgba(255,255,255,0.65)",
                margin: 0,
              }}
            >
              Complete your details to finalize your order.
            </p>
            <div
              className="chk-steps"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: "6px",
                marginTop: "14px",
                fontSize: "10px",
                fontWeight: "700",
              }}
            >
              {[ "Cart", "Address", "Shipping", "Payment" ].map((step, i) => (
                <React.Fragment key={step}>
                  {i > 0 && (
                    <span
                      className="chk-step-item"
                      style={{ color: "rgba(255,255,255,0.3)" }}
                    >
                      ›
                    </span>
                  )}
                  <span
                    className="chk-step-item"
                    style={{
                      color: i <= 1 ? "#ffffff" : "rgba(255,255,255,0.4)",
                    }}
                  >
                    <span
                      className="chk-step-btn"
                      style={{
                        background:
                          i === 1 ? "rgba(255,255,255,0.15)" : "transparent",
                        padding: i === 1 ? "3px 10px" : "3px 0",
                        borderRadius: "20px",
                        letterSpacing: "0.05em",
                        textTransform: "uppercase",
                      }}
                    >
                      {i === 0 ? (
                        <Link
                          to="/cart"
                          style={{ color: "inherit", textDecoration: "none" }}
                        >
                          {step}
                        </Link>
                      ) : (
                        step
                      )}
                    </span>
                  </span>
                </React.Fragment>
              ))}
            </div>
          </div>
        </section>

        {/* Main Content */}
        <div className="chk-main">
          <div className="chk-grid">
            {/* Left: Form */}
            <div
              className="chk-left chk-card"
              style={{ animationDelay: "0.1s" }}
            >
              <form onSubmit={handleChapa}>
                {/* Contact Information */}
                <div
                  style={{
                    background: "#ffffff",
                    borderRadius: "24px",
                    border: "1px solid #f1f5f9",
                    padding: "28px",
                    boxShadow: "0 2px 12px rgba(0,0,0,0.03)",
                    marginBottom: "24px",
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: "10px",
                      marginBottom: "24px",
                    }}
                  >
                    <div
                      style={{
                        width: "36px",
                        height: "36px",
                        borderRadius: "10px",
                        background: "rgba(20,184,166,0.1)",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        fontSize: "16px",
                      }}
                    >
                      📧
                    </div>
                    <h3
                      style={{
                        fontSize: "17px",
                        fontWeight: "800",
                        color: "#111827",
                        margin: 0,
                        letterSpacing: "-0.3px",
                      }}
                    >
                      Contact Information
                    </h3>
                  </div>

                  <div
                    style={{
                      display: "flex",
                      flexDirection: "column",
                      gap: "14px",
                    }}
                  >
                    <input
                      style={inputStyle}
                      placeholder="Email address"
                      type="email"
                      name="email"
                      value={input.email}
                      onChange={handleChange}
                      onFocus={inputFocusHandler}
                      onBlur={inputBlurHandler}
                      required
                    />
                    <input
                      style={inputStyle}
                      placeholder="Phone number"
                      type="tel"
                      name="phone"
                      value={input.phone}
                      onChange={handleChange}
                      onFocus={inputFocusHandler}
                      onBlur={inputBlurHandler}
                      required
                    />
                  </div>
                </div>

                {/* Shipping Address */}
                <div
                  style={{
                    background: "#ffffff",
                    borderRadius: "24px",
                    border: "1px solid #f1f5f9",
                    padding: "28px",
                    boxShadow: "0 2px 12px rgba(0,0,0,0.03)",
                    marginBottom: "24px",
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: "10px",
                      marginBottom: "24px",
                    }}
                  >
                    <div
                      style={{
                        width: "36px",
                        height: "36px",
                        borderRadius: "10px",
                        background: "rgba(20,184,166,0.1)",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        fontSize: "16px",
                      }}
                    >
                      📦
                    </div>
                    <h3
                      style={{
                        fontSize: "17px",
                        fontWeight: "800",
                        color: "#111827",
                        margin: 0,
                        letterSpacing: "-0.3px",
                      }}
                    >
                      Shipping Address
                    </h3>
                  </div>

                  <div
                    style={{
                      display: "flex",
                      flexDirection: "column",
                      gap: "14px",
                    }}
                  >
                    <div
                      style={{
                        display: "grid",
                        gridTemplateColumns: "1fr 1fr",
                        gap: "14px",
                      }}
                    >
                      <input
                        style={inputStyle}
                        placeholder="First name"
                        type="text"
                        name="firstname"
                        value={input.firstname}
                        onChange={handleChange}
                        onFocus={inputFocusHandler}
                        onBlur={inputBlurHandler}
                      />
                      <input
                        style={inputStyle}
                        placeholder="Last name"
                        type="text"
                        name="lastname"
                        value={input.lastname}
                        onChange={handleChange}
                        onFocus={inputFocusHandler}
                        onBlur={inputBlurHandler}
                      />
                    </div>
                    <input
                      style={inputStyle}
                      placeholder="City"
                      type="text"
                      name="city"
                      value={input.city}
                      onChange={handleChange}
                      onFocus={inputFocusHandler}
                      onBlur={inputBlurHandler}
                    />
                    <input
                      style={inputStyle}
                      placeholder="Full address"
                      type="text"
                      name="address"
                      value={input.address}
                      onChange={handleChange}
                      onFocus={inputFocusHandler}
                      onBlur={inputBlurHandler}
                    />
                    <div
                      style={{
                        display: "grid",
                        gridTemplateColumns: "1fr 1fr",
                        gap: "14px",
                      }}
                    >
                      <input
                        style={inputStyle}
                        placeholder="Country"
                        type="text"
                        name="country"
                        value={input.country}
                        onChange={handleChange}
                        onFocus={inputFocusHandler}
                        onBlur={inputBlurHandler}
                      />
                      <input
                        style={inputStyle}
                        placeholder="Postal code"
                        type="text"
                        name="postalCode"
                        value={input.postalCode}
                        onChange={handleChange}
                        onFocus={inputFocusHandler}
                        onBlur={inputBlurHandler}
                      />
                    </div>

                    <label
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        marginTop: "8px",
                        fontSize: "13px",
                        fontWeight: "600",
                        color: "#6b7280",
                        cursor: "pointer",
                      }}
                    >
                      <input
                        type="checkbox"
                        name="saveInfo"
                        style={{
                          width: "18px",
                          height: "18px",
                          accentColor: "#14b8a6",
                          borderRadius: "4px",
                          cursor: "pointer",
                        }}
                      />
                      Save this information for next time
                    </label>
                  </div>
                </div>

                {/* Prescription Upload */}
                {requiresPrescription && (
                  <div
                    style={{
                      background: "#ffffff",
                      borderRadius: "24px",
                      border: "1px solid #f87171",
                      padding: "28px",
                      boxShadow: "0 2px 12px rgba(248,113,113,0.1)",
                      marginBottom: "24px",
                    }}
                  >
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        marginBottom: "16px",
                      }}
                    >
                      <div
                        style={{
                          width: "36px",
                          height: "36px",
                          borderRadius: "10px",
                          background: "rgba(248,113,113,0.1)",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          fontSize: "16px",
                        }}
                      >
                        📄
                      </div>
                      <h3
                        style={{
                          fontSize: "17px",
                          fontWeight: "800",
                          color: "#991b1b",
                          margin: 0,
                          letterSpacing: "-0.3px",
                        }}
                      >
                        Prescription Required
                      </h3>
                    </div>
                    <p style={{ fontSize: "13px", color: "#b91c1c", marginBottom: "16px", lineHeight: "1.5" }}>
                      One or more items in your cart require a valid prescription. Please verify and upload a clear image of your medical prescription to proceed.
                    </p>
                    
                    <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
                      <input
                        type="file"
                        multiple
                        accept="image/*"
                        onChange={handlePrescriptionUpload}
                        disabled={uploadingPrescription}
                        style={{
                          width: "100%",
                          padding: "10px",
                          fontSize: "14px",
                          border: "1.5px dashed #f87171",
                          borderRadius: "14px",
                          background: "#fef2f2",
                          cursor: uploadingPrescription ? "not-allowed" : "pointer",
                          color: "#991b1b"
                        }}
                      />
                      {uploadingPrescription && (
                        <p style={{ fontSize: "12px", color: "#d97706", margin: 0, fontWeight: "600" }}>Uploading prescription...</p>
                      )}
                      {prescriptionImages.length > 0 && (
                        <div style={{ display: "flex", gap: "10px", flexWrap: "wrap", marginTop: "10px" }}>
                          {prescriptionImages.map((img, idx) => (
                            <div key={idx} style={{ position: "relative" }}>
                                <img 
                                src={img.secure_url} 
                                alt="Uploaded" 
                                style={{ width: "64px", height: "64px", objectFit: "cover", borderRadius: "8px", border: "1px solid #f87171" }} 
                                />
                                <button
                                type="button"
                                style={{
                                    position: "absolute",
                                    top: "-6px",
                                    right: "-6px",
                                    background: "#ef4444",
                                    color: "white",
                                    border: "none",
                                    borderRadius: "50%",
                                    width: "20px",
                                    height: "20px",
                                    fontSize: "10px",
                                    cursor: "pointer",
                                    display: "flex",
                                    alignItems: "center",
                                    justifyContent: "center"
                                }}
                                onClick={() => setPrescriptionImages(prev => prev.filter((_, i) => i !== idx))}
                                >
                                ✕
                                </button>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                )}

                {/* Action Buttons */}
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "12px",
                  }}
                >
                  <button
                    type="submit"
                    style={{
                      width: "100%",
                      padding: "18px",
                      background: "linear-gradient(135deg, #14b8a6, #0d9488)",
                      color: "#ffffff",
                      border: "none",
                      borderRadius: "16px",
                      fontSize: "15px",
                      fontWeight: "800",
                      letterSpacing: "0.1em",
                      textTransform: "uppercase",
                      cursor: "pointer",
                      boxShadow: "0 8px 24px rgba(20,184,166,0.3)",
                      transition: "all 0.2s ease",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: "10px",
                    }}
                    onMouseOver={(e) => {
                      e.currentTarget.style.transform = "translateY(-2px)";
                      e.currentTarget.style.boxShadow =
                        "0 12px 32px rgba(20,184,166,0.35)";
                    }}
                    onMouseOut={(e) => {
                      e.currentTarget.style.transform = "translateY(0)";
                      e.currentTarget.style.boxShadow =
                        "0 8px 24px rgba(20,184,166,0.3)";
                    }}
                  >
                    🔒 Pay Securely — {totalAmount.toLocaleString()} ETB
                  </button>
                  <Link
                    to="/cart"
                    style={{
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: "8px",
                      width: "100%",
                      padding: "14px",
                      background: "#f8fafc",
                      color: "#6b7280",
                      border: "1px solid #e2e8f0",
                      borderRadius: "14px",
                      fontSize: "13px",
                      fontWeight: "700",
                      textDecoration: "none",
                      transition: "all 0.2s",
                    }}
                    onMouseOver={(e) => {
                      e.currentTarget.style.background = "#f1f5f9";
                      e.currentTarget.style.color = "#374151";
                    }}
                    onMouseOut={(e) => {
                      e.currentTarget.style.background = "#f8fafc";
                      e.currentTarget.style.color = "#6b7280";
                    }}
                  >
                    ← Return to Cart
                  </Link>
                </div>
              </form>
            </div>

            {/* Right: Order Summary */}
            <div className="chk-card" style={{ animationDelay: "0.2s" }}>
              <div
                style={{
                  background: "#ffffff",
                  borderRadius: "24px",
                  border: "1px solid #f1f5f9",
                  padding: "28px",
                  boxShadow: "0 2px 12px rgba(0,0,0,0.03)",
                  position: "sticky",
                  top: "100px",
                }}
              >
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "10px",
                    marginBottom: "24px",
                  }}
                >
                  <div
                    style={{
                      width: "36px",
                      height: "36px",
                      borderRadius: "10px",
                      background: "rgba(20,184,166,0.1)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      fontSize: "16px",
                    }}
                  >
                    🛒
                  </div>
                  <h3
                    style={{
                      fontSize: "17px",
                      fontWeight: "800",
                      color: "#111827",
                      margin: 0,
                      letterSpacing: "-0.3px",
                    }}
                  >
                    Order Summary
                  </h3>
                  <span
                    style={{
                      marginLeft: "auto",
                      fontSize: "12px",
                      fontWeight: "700",
                      color: "#14b8a6",
                      background: "rgba(20,184,166,0.08)",
                      padding: "3px 10px",
                      borderRadius: "20px",
                    }}
                  >
                    {cartItems.length} items
                  </span>
                </div>

                {/* Cart Items */}
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "14px",
                    marginBottom: "24px",
                  }}
                >
                  {cartItems.map((item, index) => (
                    <div
                      key={index}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "14px",
                        padding: "12px",
                        background: "#f8fafc",
                        borderRadius: "16px",
                        transition: "background 0.2s",
                      }}
                      onMouseOver={(e) =>
                        (e.currentTarget.style.background = "#f1f5f9")
                      }
                      onMouseOut={(e) =>
                        (e.currentTarget.style.background = "#f8fafc")
                      }
                    >
                      <div
                        style={{
                          width: "60px",
                          height: "60px",
                          flexShrink: 0,
                          borderRadius: "12px",
                          overflow: "hidden",
                          position: "relative",
                          background: "#fff",
                          border: "1px solid #e2e8f0",
                        }}
                      >
                        <img
                          src={
                            item?.productId?.colors?.[0]?.images?.[0]
                              ?.secure_url || "default-image-url.jpg"
                          }
                          alt={item?.productId?.title}
                          style={{
                            width: "100%",
                            height: "100%",
                            objectFit: "cover",
                          }}
                        />
                        <span
                          style={{
                            position: "absolute",
                            top: "-6px",
                            right: "-6px",
                            width: "22px",
                            height: "22px",
                            borderRadius: "50%",
                            background: "#14b8a6",
                            color: "#fff",
                            fontSize: "10px",
                            fontWeight: "800",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            border: "2px solid #fff",
                          }}
                        >
                          {item.quantity}
                        </span>
                      </div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <p
                          style={{
                            fontSize: "13px",
                            fontWeight: "700",
                            color: "#111827",
                            margin: "0 0 2px",
                            overflow: "hidden",
                            textOverflow: "ellipsis",
                            whiteSpace: "nowrap",
                          }}
                        >
                          {item?.productId?.title}
                        </p>
                        <p
                          style={{
                            fontSize: "11px",
                            color: "#9ca3af",
                            margin: 0,
                            fontWeight: "500",
                          }}
                        >
                          {item?.productId?.category}
                        </p>
                      </div>
                      <span
                        style={{
                          fontSize: "14px",
                          fontWeight: "800",
                          color: "#111827",
                          whiteSpace: "nowrap",
                        }}
                      >
                        {(
                          item?.productId?.price * item.quantity
                        ).toLocaleString()}{" "}
                        <small style={{ color: "#9ca3af", fontSize: "10px" }}>
                          ETB
                        </small>
                      </span>
                    </div>
                  ))}
                </div>

                {/* Discount Code */}
                <div
                  style={{
                    display: "flex",
                    gap: "8px",
                    marginBottom: "24px",
                  }}
                >
                  <input
                    type="text"
                    placeholder="Gift card or discount code"
                    style={{
                      ...inputStyle,
                      flex: 1,
                      padding: "12px 16px",
                      fontSize: "13px",
                    }}
                    onFocus={inputFocusHandler}
                    onBlur={inputBlurHandler}
                  />
                  <button
                    style={{
                      padding: "12px 20px",
                      background: "#14b8a6",
                      color: "#fff",
                      border: "none",
                      borderRadius: "14px",
                      fontSize: "12px",
                      fontWeight: "800",
                      letterSpacing: "0.05em",
                      textTransform: "uppercase",
                      cursor: "pointer",
                      transition: "background 0.2s",
                      whiteSpace: "nowrap",
                    }}
                    type="button"
                    onMouseOver={(e) =>
                      (e.currentTarget.style.background = "#0d9488")
                    }
                    onMouseOut={(e) =>
                      (e.currentTarget.style.background = "#14b8a6")
                    }
                  >
                    Apply
                  </button>
                </div>

                {/* Totals */}
                <div
                  style={{
                    borderTop: "1px solid #f1f5f9",
                    paddingTop: "20px",
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                      marginBottom: "12px",
                    }}
                  >
                    <span
                      style={{
                        fontSize: "13px",
                        fontWeight: "600",
                        color: "#6b7280",
                      }}
                    >
                      Subtotal
                    </span>
                    <span
                      style={{
                        fontSize: "14px",
                        fontWeight: "700",
                        color: "#111827",
                      }}
                    >
                      {totalAmount.toLocaleString()} ETB
                    </span>
                  </div>
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                      marginBottom: "16px",
                    }}
                  >
                    <span
                      style={{
                        fontSize: "13px",
                        fontWeight: "600",
                        color: "#6b7280",
                      }}
                    >
                      Shipping
                    </span>
                    <span
                      style={{
                        fontSize: "12px",
                        fontWeight: "600",
                        color: "#14b8a6",
                      }}
                    >
                      Calculated at next step
                    </span>
                  </div>
                  <div
                    style={{
                      height: "1px",
                      background: "#f1f5f9",
                      marginBottom: "16px",
                    }}
                  />
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "flex-end",
                    }}
                  >
                    <span
                      style={{
                        fontSize: "16px",
                        fontWeight: "800",
                        color: "#111827",
                      }}
                    >
                      Total
                    </span>
                    <div style={{ textAlign: "right" }}>
                      <span
                        style={{
                          fontSize: "28px",
                          fontWeight: "900",
                          color: "#14b8a6",
                          letterSpacing: "-1px",
                        }}
                      >
                        {totalAmount.toLocaleString()}
                      </span>
                      <span
                        style={{
                          fontSize: "14px",
                          fontWeight: "700",
                          color: "#6b7280",
                          marginLeft: "4px",
                        }}
                      >
                        ETB
                      </span>
                    </div>
                  </div>
                </div>

                {/* Trust Badge */}
                <div
                  style={{
                    marginTop: "24px",
                    padding: "16px",
                    background: "#f0fdfa",
                    borderRadius: "16px",
                    display: "flex",
                    alignItems: "center",
                    gap: "12px",
                  }}
                >
                  <span style={{ fontSize: "20px" }}>🛡️</span>
                  <div>
                    <p
                      style={{
                        fontSize: "12px",
                        fontWeight: "700",
                        color: "#0d9488",
                        margin: "0 0 2px",
                      }}
                    >
                      Secure Checkout
                    </p>
                    <p
                      style={{
                        fontSize: "11px",
                        color: "#6b7280",
                        margin: 0,
                        lineHeight: 1.5,
                      }}
                    >
                      Your payment is protected with industry-standard
                      encryption.
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <Footer />
      </main>
    </>
  );
}

export default Checkout;
